args.sparql:
SELECT DISTINCT ?team WHERE {
  ?team rdfs:label ?label .
  FILTER (langMatches(lang(?label), 'en') && regex(?label, 'Sporting de Gijón', 'i'))
  ?team wdt:P31 wd:Q7692201 .
}

SELECT DISTINCT ?colorLabel WHERE {
  wd:Q188933 wdt:P1101 ?kitColor .
  ?kitColor rdfs:label ?colorLabel .
  FILTER (LANG(?colorLabel) = 'en')
}
